// 提取库存信息
const order = $input.first().json;

const skus = order.items.map(item => item.sku);

return skus.map(sku => ({json: {sku, order_id: order.order_id}}));

// Prophet时间序列预测 (简化版)
const sku = $input.first().json.sku;
const inventory = $('查询当前库存').first().json;
const salesTrend = $('查询销售趋势').all().map(i => i.json);

// 计算平均日销量
const totalSales = salesTrend.reduce((sum, day) => sum + (day.daily_sales || 0), 0);
const avgDailySales = salesTrend.length > 0 ? totalSales / salesTrend.length : 1;

// 计算销量趋势 (简单线性回归)
let trendSlope = 0;
if (salesTrend.length > 7) {
  const recent = salesTrend.slice(-30);
  const older = salesTrend.slice(-60, -30);
  const recentAvg = recent.reduce((sum, d) => sum + d.daily_sales, 0) / recent.length;
  const olderAvg = older.reduce((sum, d) => sum + d.daily_sales, 0) / older.length;
  trendSlope = (recentAvg - olderAvg) / olderAvg;
}

// 季节性调整
const month = new Date().getMonth();
const seasonalityFactor = [0.8, 0.9, 1.0, 1.1, 1.2, 1.3, 1.2, 1.1, 1.0, 0.9, 1.0, 1.4][month];

// 预测未来30天需求
const forecastDays = 30;
const baseForecast = avgDailySales * (1 + trendSlope) * seasonalityFactor;
const forecast30Days = baseForecast * forecastDays;

// 计算库存参数
const leadTime = inventory.supplier_lead_time_days || 14;  // 供应商交货时间
const leadTimeDemand = baseForecast * leadTime;
const safetyStock = leadTimeDemand * 0.5;  // 50%安全库存
const reorderPoint = leadTimeDemand + safetyStock;

// 当前库存状态
const currentStock = inventory.available_quantity || 0;
const inTransit = inventory.in_transit_quantity || 0;
const totalStock = currentStock + inTransit;

// 库存天数
const daysOfStock = baseForecast > 0 ? totalStock / baseForecast : 999;

// 是否需要补货
const needsReorder = totalStock < reorderPoint;
const recommendedOrderQty = needsReorder ? Math.ceil(forecast30Days + safetyStock - totalStock) : 0;

// 滞销检测
const isSlowMoving = avgDailySales < 0.5 && currentStock > 30;

const result = {
  sku: sku,
  current_stock: currentStock,
  in_transit: inTransit,
  total_available: totalStock,
  avg_daily_sales: parseFloat(avgDailySales.toFixed(2)),
  forecast_30_days: parseFloat(forecast30Days.toFixed(0)),
  days_of_stock: parseFloat(daysOfStock.toFixed(1)),
  reorder_point: parseFloat(reorderPoint.toFixed(0)),
  safety_stock: parseFloat(safetyStock.toFixed(0)),
  needs_reorder: needsReorder,
  recommended_order_qty: recommendedOrderQty,
  is_slow_moving: isSlowMoving,
  stock_level: currentStock,  // For compatibility
  alerts: [],
  timestamp: new Date().toISOString()
};

// 生成告警
if (daysOfStock < 7) {
  result.alerts.push('CRITICAL: Less than 7 days of stock');
}
if (needsReorder) {
  result.alerts.push(`Reorder recommended: ${recommendedOrderQty} units`);
}
if (isSlowMoving) {
  result.alerts.push('Slow-moving inventory detected');
}

return [{json: result}];

